// ==========================================================================
// DEVELOPER — picks one To Do task and ships a PR to develop
// Pipeline: lock card -> read repo/track/stack -> Claude generates files ->
// branch task/<cardId> from develop -> commit files -> open PR -> write docs ->
// release Waiting-API deps after the last backend task -> move card to In Review + notify.
// If the task branch already exists it enters "fix mode" (patch, do not rewrite).
// ==========================================================================

const TK = $env.TRELLO_KEY,
  TT = $env.TRELLO_TOKEN,
  BOARD = $env.TRELLO_BOARD_ID;
const L = {
  todo: $env.TRELLO_LIST_TODO,
  prog: $env.TRELLO_LIST_INPROGRESS,
  wait: $env.TRELLO_LIST_WAITING,
  review: $env.TRELLO_LIST_INREVIEW,
  owner: $env.TRELLO_LIST_OWNER,
};
const GHTOKEN = $env.GITHUB_TOKEN,
  OWNER_CHAT = $env.OWNER_CHAT,
  BALE = $env.BALE_BOT_TOKEN;
const CLAUDE_BRIDGE = 'http://host.docker.internal:8787/v1/messages';
const req = (o) => this.helpers.httpRequest(o);
const tUrl = (p) => 'https://api.trello.com/1/' + p + (p.includes('?') ? '&' : '?') + 'key=' + TK + '&token=' + TT;
const tGet = async (p) => {
  try {
    return await req({ method: 'GET', url: tUrl(p), json: true });
  } catch (e) {
    return [];
  }
};
const tPost = async (p) => req({ method: 'POST', url: tUrl(p), json: true });
const tPut = async (p) => req({ method: 'PUT', url: tUrl(p), json: true });
const tDel = async (p) => {
  try {
    return await req({ method: 'DELETE', url: tUrl(p), json: true });
  } catch (e) {
    return null;
  }
};
const bale = async (chat, text) => {
  try {
    await req({
      method: 'POST',
      url: 'https://tapi.bale.ai/bot' + BALE + '/sendMessage',
      body: JSON.stringify({ chat_id: chat, text }),
      headers: { 'content-type': 'application/json' },
      json: false,
    });
  } catch (e) {}
};
const claude = async (prompt, mt) => {
  const r = await req({
    method: 'POST',
    url: CLAUDE_BRIDGE,
    body: JSON.stringify({
      model: 'claude-opus-4-8',
      max_tokens: mt || 3000,
      messages: [{ role: 'user', content: prompt }],
    }),
    headers: { 'content-type': 'application/json' },
    json: false,
  });
  const j = typeof r === 'string' ? JSON.parse(r) : r;
  return (j.content && j.content[0] && j.content[0].text) || '';
};
const strip = (s) =>
  String(s || '')
    .replace(/```json|```/g, '')
    .trim();
const jparse = (t) => {
  let s = strip(t);
  try {
    return JSON.parse(s);
  } catch (e) {}
  let a = s.indexOf('{'),
    b = s.lastIndexOf('}');
  if (a >= 0 && b > a) {
    try {
      return JSON.parse(s.slice(a, b + 1));
    } catch (e) {}
  }
  let c = s.indexOf('['),
    d = s.lastIndexOf(']');
  if (c >= 0 && d > c) {
    try {
      return JSON.parse(s.slice(c, d + 1));
    } catch (e) {}
  }
  return null;
};
const enc = (s) => Buffer.from(s || '', 'utf8').toString('base64');
const normRepo = (u) =>
  String(u || '')
    .trim()
    .replace(/\.git$/, '')
    .replace(/^https?:\/\/github\.com\//i, '')
    .replace(/^github\.com\//i, '');
const gh = async (method, path, body, raw) => {
  const r = await req({
    method,
    url: 'https://api.github.com' + path,
    headers: {
      Authorization: 'Bearer ' + GHTOKEN,
      Accept: raw ? 'application/vnd.github.raw+json' : 'application/vnd.github+json',
      'User-Agent': 'n8n-bot',
    },
    body: body ? JSON.stringify(body) : undefined,
    json: false,
  });
  if (raw) return typeof r === 'string' ? r : JSON.stringify(r);
  try {
    return typeof r === 'string' ? JSON.parse(r) : r;
  } catch (e) {
    return r;
  }
};
const meta = (d) => {
  d = String(d || '');
  const g = (re) => {
    const m = d.match(re);
    return m ? m[1].trim() : '';
  };
  return { repo: normRepo(g(/repo:\s*(\S+)/)), project: g(/project:\s*(.+)/), ref: g(/ref:\s*(\S+)/) };
};
const trackOf = (name) => {
  const m = String(name || '').match(/^\[(backend|frontend|mobile)\]/);
  return m ? m[1] : 'backend';
};
const CI_YML =
  "name: CI\non:\n  pull_request:\n    branches: [ develop ]\njobs:\n  backend:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-python@v5\n        with: { python-version: '3.12' }\n      - name: backend tests\n        run: |\n          if [ -d backend ]; then\n            cd backend\n            pip install -r requirements.txt 2>/dev/null || pip install django djangorestframework pytest pytest-django\n            python -m pytest -q\n          else echo \"no backend yet\"; fi\n  frontend:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-node@v4\n        with: { node-version: '20' }\n      - name: frontend tests\n        run: |\n          if [ -f frontend/package.json ]; then\n            cd frontend\n            npm ci || npm install\n            npm test -- --watch=false --browsers=ChromeHeadless\n          else echo \"no frontend yet\"; fi\n  mobile:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-java@v4\n        with: { distribution: 'temurin', java-version: '17' }\n      - name: mobile tests\n        run: |\n          if [ -f mobile/gradlew ]; then\n            cd mobile\n            chmod +x gradlew && ./gradlew test\n          else echo \"no mobile yet\"; fi\n";

// Each platform stack is read from stacks/<track>.md (served by claude-bridge.js).
// Falls back to the built-in default if missing/empty so the system never stalls.
const STACK_DEFAULT = {
  backend:
    'نقش: Backend Developer. استک: Python + Django + Django REST Framework با معماری تمیز. کل کد زیر پوشه‌ی backend/ و یک پکیج کامل و قابل‌اجرا (requirements.txt شامل django/djangorestframework/pytest/pytest-django، settings، manage.py در صورت نیاز). حداقل ۳ unit test با pytest در backend/ بنویس.',
  frontend:
    'نقش: Frontend Developer. استک: Angular (standalone components، TypeScript، RxJS). کل کد زیر پوشه‌ی frontend/ و package.json با اسکریپت test. سرویس HTTP بر اساس مستندات API. حداقل ۳ unit test (jasmine/karma یا jest) بنویس.',
  mobile:
    'نقش: Mobile Developer. استک: Kotlin Multiplatform + Compose Multiplatform (Android/iOS). کل کد زیر پوشه‌ی mobile/ با Gradle. لایه شبکه با Ktor بر اساس مستندات API. حداقل ۳ unit test (kotlin.test) بنویس.',
};
const readStack = async (t) => {
  try {
    const s = await req({ method: 'GET', url: 'http://host.docker.internal:8787/stack/' + t, json: false });
    const v = String(s || '').trim();
    return v || STACK_DEFAULT[t];
  } catch (e) {
    return STACK_DEFAULT[t];
  }
};
const readRole = async (role) => {
  try {
    const s = await req({ method: 'GET', url: 'http://host.docker.internal:8787/role/' + role, json: false });
    return String(s || '').trim();
  } catch (e) {
    return '';
  }
};
let todo = await tGet('lists/' + L.todo + '/cards?fields=name,desc');
todo = todo.filter((c) => c && c.id);
if (!todo.length) return [{ json: { idle: 1 } }];
const inProg = await tGet('lists/' + L.prog + '/cards?fields=id');
const inRev = await tGet('lists/' + L.review + '/cards?fields=id');
if (inProg.length || inRev.length)
  return [{ json: { idle: 1, reason: 'task in flight — waiting for current task to finish' } }];
todo.sort((a, b) => (trackOf(a.name) === 'backend' ? 0 : 1) - (trackOf(b.name) === 'backend' ? 0 : 1));
const c = todo[0];
const mm = meta(c.desc);
if (!mm.repo) {
  await tPut('cards/' + c.id + '?idList=' + L.review);
  return [{ json: { noRepo: c.id } }];
}
const [o, r] = mm.repo.split('/');
const track = trackOf(c.name);
const dir = track + '/';
await tPut('cards/' + c.id + '?idList=' + L.prog);
const branch = 'task/' + c.id;
// "fix" mode: if the task branch already exists, this card came back for a bug fix
let isFix = false;
try {
  await gh('GET', '/repos/' + o + '/' + r + '/git/ref/heads/' + branch);
  isFix = true;
} catch (e) {}
// failure reason/log from the card's latest Trello comments (left by the Tech Lead)
let failLog = '';
if (isFix) {
  try {
    const acts = await tGet('cards/' + c.id + '/actions?filter=commentCard&limit=6');
    failLog = (acts || [])
      .map((a) => a && a.data && a.data.text)
      .filter(Boolean)
      .slice(0, 3)
      .join('\n----\n');
  } catch (e) {}
}
// current code on the branch (this track only) so Claude fixes rather than rewrites
let curCode = '';
if (isFix) {
  try {
    const tree = (await gh('GET', '/repos/' + o + '/' + r + '/git/trees/' + branch + '?recursive=1')).tree || [];
    const blobs = tree.filter((t) => t && t.type === 'blob' && String(t.path || '').startsWith(dir)).slice(0, 12);
    for (const b of blobs) {
      let cont = '';
      try {
        cont = await gh(
          'GET',
          '/repos/' + o + '/' + r + '/contents/' + encodeURIComponent(b.path) + '?ref=' + branch,
          null,
          true,
        );
      } catch (e) {}
      curCode += 'FILE: ' + b.path + '\n' + String(cont).slice(0, 2500) + '\n\n';
    }
    curCode = curCode.slice(0, 16000);
  } catch (e) {}
}
let apiDocs = '';
if (track !== 'backend') {
  try {
    apiDocs = await gh('GET', '/repos/' + o + '/' + r + '/contents/docs/api/API.md?ref=develop', null, true);
  } catch (e) {}
}
const stackText = await readStack(track);
const devRole = (await readRole('developer')) || '';
const base =
  (devRole ? devRole + '\n\n' : '') +
  stackText +
  '\nنام پروژه: ' +
  (mm.project || '') +
  (mm.ref ? '\nمرجع: ' + mm.ref : '') +
  '\nهمه‌ی فایل‌ها زیر پوشه‌ی ' +
  dir +
  ' باشند.' +
  (apiDocs ? '\n\nمستندات API:\n' + apiDocs : '');
const prompt = isFix
  ? base +
    '\n\n⚠️ این تسک قبلاً پیاده‌سازی شده ولی باگ/خطای build یا test داشت و برگشته. وظیفه‌ات رفع باگ است نه بازنویسی از صفر.\n\nخطاها/دلیل برگشت:\n' +
    (failLog || '(نامشخص — کد را بازبینی و مشکلات احتمالی build/test را رفع کن)') +
    '\n\nکد فعلی:\n' +
    (curCode || '(در دسترس نبود)') +
    '\n\nتسک:\n' +
    c.name +
    '\n' +
    c.desc +
    '\n\nفقط فایل‌هایی که باید تغییر/اضافه شوند را برگردان؛ هر content نسخه‌ی کامل و نهایی فایل باشد. خروجی فقط JSON با کلید files (آرایه‌ای از {path, content}). path باید با ' +
    dir +
    ' شروع شود. فقط JSON.'
  : base +
    '\n\nتسک:\n' +
    c.name +
    '\n' +
    c.desc +
    '\n\nخروجی فقط JSON با کلید files (آرایه‌ای از {path, content}). path باید با ' +
    dir +
    ' شروع شود. فقط JSON.';
let rawF = '';
try {
  rawF = await claude(prompt, 6000);
} catch (e) {
  rawF = '';
}
const pf = jparse(rawF);
let files = (pf && pf.files) || [];
if (!files.length) {
  await tPut('cards/' + c.id + '?idList=' + L.todo);
  return [{ json: { noFiles: c.id } }];
}
let baseSha;
try {
  baseSha = (await gh('GET', '/repos/' + o + '/' + r + '/git/ref/heads/develop')).object.sha;
} catch (e) {
  baseSha = (await gh('GET', '/repos/' + o + '/' + r + '/git/ref/heads/main')).object.sha;
}
try {
  await gh('POST', '/repos/' + o + '/' + r + '/git/refs', { ref: 'refs/heads/' + branch, sha: baseSha });
} catch (e) {}
for (const f of files) {
  let p = f.path || '';
  if (!p.startsWith(dir)) p = dir + p.replace(/^\/+/, '');
  let sha;
  try {
    const ex = await gh('GET', '/repos/' + o + '/' + r + '/contents/' + encodeURIComponent(p) + '?ref=' + branch);
    sha = ex.sha;
  } catch (e) {}
  try {
    await gh('PUT', '/repos/' + o + '/' + r + '/contents/' + encodeURIComponent(p), {
      message: 'feat: ' + c.name,
      content: enc(f.content || ''),
      branch,
      sha,
    });
  } catch (e) {}
}
let pr;
try {
  pr = await gh('POST', '/repos/' + o + '/' + r + '/pulls', {
    title: c.name,
    head: branch,
    base: 'develop',
    body: 'Trello: ' + c.id + '\nTrack: ' + track + '\n\n' + (c.desc || ''),
  });
} catch (e) {
  await bale(OWNER_CHAT, '⚠️ ساخت PR ناموفق برای ' + c.name + ': ' + e.message);
  await tPut('cards/' + c.id + '?idList=' + L.todo);
  return [{ json: { prErr: c.id } }];
}
if (isFix) {
  try {
    const chg = files
      .map((f) => f.path || '')
      .filter(Boolean)
      .slice(0, 12)
      .join('، ');
    await tPost(
      'cards/' +
        c.id +
        '/actions/comments?text=' +
        encodeURIComponent('🛠️ فیکس اعمال شد (PR #' + pr.number + '). فایل‌های تغییر‌یافته: ' + (chg || '-')),
    );
  } catch (e) {}
}
// documentation
let docText = '';
try {
  docText = await claude(
    'برای این تسک یک مستند Markdown بنویس. اگر backend است مستند API کامل (هر endpoint با method/مسیر/نمونه request/response). فقط Markdown. تسک: ' +
      c.name +
      '\n' +
      c.desc,
    2500,
  );
} catch (e) {}
const docPath = 'docs/' + track + '/' + c.id + '.md';
try {
  let sha;
  try {
    const ex = await gh('GET', '/repos/' + o + '/' + r + '/contents/' + docPath + '?ref=develop');
    sha = ex.sha;
  } catch (e) {}
  await gh('PUT', '/repos/' + o + '/' + r + '/contents/' + docPath, {
    message: 'docs: ' + c.name,
    content: enc(docText || '(بدون مستند)'),
    branch: 'develop',
    sha,
  });
} catch (e) {}
if (track === 'backend') {
  try {
    const apiP = 'docs/api/API.md';
    let prev = '',
      apiSha;
    try {
      const ex = await gh('GET', '/repos/' + o + '/' + r + '/contents/' + apiP + '?ref=develop');
      apiSha = ex.sha;
      prev = Buffer.from(ex.content, 'base64').toString('utf8');
    } catch (e) {}
    const merged = (prev ? prev + '\n\n' : '# API Documentation\n\n') + '## ' + c.name + '\n\n' + docText;
    await gh('PUT', '/repos/' + o + '/' + r + '/contents/' + apiP, {
      message: 'docs(api): ' + c.name,
      content: enc(merged),
      branch: 'develop',
      sha: apiSha,
    });
    const left = [
      ...(await tGet('lists/' + L.todo + '/cards?fields=name')),
      ...(await tGet('lists/' + L.prog + '/cards?fields=name')),
    ].filter((x) => trackOf(x.name) === 'backend' && x.id !== c.id).length;
    if (left === 0) {
      const w = await tGet('lists/' + L.wait + '/cards?fields=id');
      for (const wc of w) {
        await tPut('cards/' + wc.id + '?idList=' + L.todo);
      }
    }
  } catch (e) {}
}
await tPut('cards/' + c.id + '?idList=' + L.review);
await bale(
  OWNER_CHAT,
  (isFix ? '🔧 فیکس شد و رفت برای ریویو: ' : '👀 رفت برای ریویو: ') + c.name + '\nPR: ' + pr.html_url,
);
const WF3_HOOK = 'http://localhost:5678/webhook/tech-lead-review';
try {
  await req({
    method: 'POST',
    url: WF3_HOOK,
    body: JSON.stringify({ cardId: c.id, prNum: pr.number }),
    headers: { 'content-type': 'application/json' },
    json: false,
  });
} catch (e) {}
return [{ json: { pr: pr.number, card: c.id, track } }];
